<script lang="ts">let{data,form}=$props();let draft=$state(data.editing?.content||'');</script><svelte:head><title>博客写作｜暮色工作台</title></svelte:head><header class="studio-head"><div><p class="eyebrow">WRITING</p><h1>博客写作</h1><p>按分类整理文章，保持长期写作后的清晰结构。</p></div><div class="head-actions"><a href="/studio/post-categories">管理文章分类</a><a class="primary" href="#editor">＋ 新文章</a></div></header>{#if form?.message}<div class:success={form.success} class="notice">{form.message}</div>{/if}<div class="writing-grid"><aside class="studio-panel post-index">{#each data.posts as post}<a class:active={post.id===data.editing?.id} href={`?edit=${post.id}#editor`}><small>{post.categoryName||'未分类'} · {post.status==='draft'?'草稿':'已发布'} · {new Date(post.publishedAt).toLocaleDateString('zh-CN')}</small><b>{post.title}</b><span>{post.excerpt}</span></a>{/each}</aside><section class="studio-panel editor writing" id="editor"><form method="POST" action="?/save" enctype="multipart/form-data" class="studio-form"><input type="hidden" name="id" value={data.editing?.id||''}/><input type="hidden" name="cover" value={data.editing?.cover||''}/><input class="title-input" name="title" value={data.editing?.title||''} placeholder="文章标题" required/><div class="two"><label>文章网址标识 <small>用于生成文章链接，留空将根据标题自动生成</small><input name="slug" value={data.editing?.slug||''} placeholder="例如：my-first-note" /></label><label>文章分类<select name="categoryId" required>{#each data.categories as category}<option value={category.id} selected={category.id===data.editing?.categoryId}>{category.name}</option>{/each}</select></label></div><label>摘要<textarea name="excerpt" rows="2">{data.editing?.excerpt||''}</textarea></label><label>正文 <small>支持空行分段，以 ## 和 ### 开始创建标题</small><textarea class="writing-area" name="content" rows="22" bind:value={draft} placeholder="从这里开始写……"></textarea></label><div class="two"><label>发布时间<input name="publishedAt" type="datetime-local" value={(data.editing?.publishedAt||new Date().toISOString()).slice(0,16)} /></label><label>状态<select name="status"><option value="draft" selected={data.editing?.status!=='published'}>保存草稿</option><option value="published" selected={data.editing?.status==='published'}>立即发布</option></select></label></div><label>封面图片<input name="coverFile" type="file" accept="image/png,image/jpeg,image/webp,image/gif" /></label><label class="check"><input name="featured" type="checkbox" checked={Boolean(data.editing?.featured)}/> 设为博客重点文章</label><div class="form-actions"><button class="primary">保存文章</button>{#if data.editing}<button class="danger" formaction="?/delete" onclick={(e)=>!confirm('确定删除这篇文章？')&&e.preventDefault()}>删除文章</button>{/if}</div></form></section></div>
